function updateLoadDerived(l){$(`load-type-label-${l.id}`).textContent=l.inputType||'-';$(`load-current-${l.id}`).textContent=fmt(currentForLoad(l),2);$(`load-kw-${l.id}`).textContent=fmt(kwForLoad(l),3);$(`load-kva-${l.id}`).textContent=fmt(kvaForLoad(l),3)}
function updateLoadPositionLabel(){const root=$('loadCards'),cards=[...root.querySelectorAll('.load-card')];if(!cards.length)return;const idx=cards.reduce((best,c,i)=>Math.abs(c.offsetLeft-root.scrollLeft)<Math.abs(cards[best].offsetLeft-root.scrollLeft)?i:best,0);$('loadPositionLabel').textContent=`${idx+1} / ${cards.length}`}
function cableTable(type,label){const rows=Object.entries(CABLE_DATA[type]||{}).map(([s,info])=>({sizeSq:s,ampacity:info.ampacity,outerDiameter:info.outerDiameter,massKgKm:info.massKgKm,resistance:info.resistance,note:'参考値'}));return{note:`${label}の参考値です。許容電流・外径・質量は最終的に仕様書で確認してください。`,headers:['サイズ [sq]','許容電流 [A]','外径 [mm]','概算質量 [kg/km]','導体抵抗 [Ω/km]','備考'],keys:['sizeSq','ampacity','outerDiameter','massKgKm','resistance','note'],rows}}
