function conduitRows(ds,g){const rows=[];Object.entries(ds||{}).forEach(([type,items])=>items.forEach(info=>rows.push({group:g,conduitType:type,nominal:info.nominal,outerDiameter:info.outerDiameter??'-',innerDiameter:info.innerDiameter??'-',thicknessMm:info.thicknessMm??'-',unitMassKgM:info.unitMassKgM??'-',length:info.lengthM?`${info.lengthM}m`:info.lengthMm?`${info.lengthMm}mm`:info.coilLengthM?`${info.coilLengthM}m/巻`:'-',coilMassKg:info.coilMassKg??'-',minBendRadiusMm:info.minBendRadiusMm??'-',note:info.note||(info.coatingThicknessMm?`膜厚 ${info.coatingThicknessMm}mm`:'' )})));return rows}
function conduitPayload(ds,g,note){return{type:'table',note,headers:['分類','配管種類','呼び','外径 [mm]','内径/近似内径 [mm]','厚さ [mm]','単位質量 [kg/m]','長さ','巻質量 [kg]','最小曲げ半径 [mm]','備考'],keys:['group','conduitType','nominal','outerDiameter','innerDiameter','thicknessMm','unitMassKgM','length','coilMassKg','minBendRadiusMm','note'],rows:conduitRows(ds,g)}}
