function formulaHtml(kind){const input=(name,label,value='',step='any')=>`<label><span>${label}</span><input data-name="${name}" type="number" inputmode="decimal" step="${step}" value="${value}"></label>`;const select=(name,label,opts)=>`<label><span>${label}</span><select data-name="${name}">${opts.map(o=>`<option value="${o[0]}">${o[1]}</option>`).join('')}</select></label>`;let title='',formula='',fields='';if(kind==='threePhaseCurrent'){title='三相3線式 電流計算';formula='I = P × 1000 ÷ (√3 × V × cosθ × η)';fields=input('kw','負荷容量 P [kW]','10.55')+input('voltage','電圧 V [V]','440')+input('pf','力率 cosθ','0.85')+input('eff','効率 η','0.90')}else if(kind==='singlePhaseCurrent'){title='単相2線式 電流計算';formula='I = P × 1000 ÷ (V × cosθ × η)';fields=input('kw','負荷容量 P [kW]','1.5')+input('voltage','電圧 V [V]','200')+input('pf','力率 cosθ','0.9')+input('eff','効率 η','1.0')}else if(kind==='kvaConversion'){title='VA / kVA換算';formula='三相 VA = √3 × V × I、単相 VA = V × I';fields=select('phase','方式',[['3','三相'],['1','単相']])+input('voltage','電圧 V [V]','200')+input('current','電流 I [A]','30')}else if(kind==='voltageDrop'){title='電圧降下計算';formula='三相 e = √3 × I × R × L ÷ 1000、単相 e = 2 × I × R × L ÷ 1000';fields=select('phase','方式',[['3','三相'],['1','単相']])+input('current','電流 I [A]','30')+input('length','電線長 L [m]','100')+input('resistance','導体抵抗 R [Ω/km]','1.34')+input('voltage','使用電圧 V [V]','200')}else if(kind==='voltageDropPercent'){title='電圧降下率';formula='電圧降下率 [%] = 電圧降下 V ÷ 使用電圧 V × 100';fields=input('drop','電圧降下 [V]','5')+input('voltage','使用電圧 [V]','200')}else if(kind==='cableMargin'){title='ケーブル裕度';formula='ケーブル裕度 [%] = (補正後許容電流 − 設計電流) ÷ 補正後許容電流 × 100';fields=input('allow','補正後許容電流 [A]','100')+input('design','設計電流 [A]','75')}else if(kind==='breakerMargin'){title='主幹裕度';formula='主幹裕度 [%] = (主幹開閉器定格 − 負荷電流) ÷ 主幹開閉器定格 × 100';fields=input('breaker','主幹開閉器定格 [A]','100')+input('current','負荷電流 [A]','75')}else if(kind==='conduitFill'){title='配管選定計算式';formula='占積率 [%] = ケーブル総断面積 ÷ 配管内断面積 × 100';fields=[1,2,3,4].map(i=>input(`od${i}`,`ケーブル${i} 外径 [mm]`,i===1?'18.5':'')+input(`count${i}`,`ケーブル${i} 本数`,i===1?'3':'')).join('')+input('inner','配管内径 [mm]','35.0')}return`<div class="formula-box" data-kind="${kind}"><h4>${escapeHtml(title)}</h4><div class="formula-line">${escapeHtml(formula)}</div><div class="grid two top-gap">${fields}</div><button type="button" class="primary full top-gap formula-calc-btn">計算する</button><div class="calc-result top-gap">計算結果：-</div></div>`}
function runFormulaCalc(box){const kind=box.dataset.kind;const v=n=>num(box.querySelector(`[data-name="${n}"]`)?.value);let html='';if(kind==='threePhaseCurrent'){const I=v('kw')*1000/(Math.sqrt(3)*v('voltage')*v('pf')*v('eff'));html=`電流：${fmt(I,2)} A`}else if(kind==='singlePhaseCurrent'){const I=v('kw')*1000/(v('voltage')*v('pf')*v('eff'));html=`電流：${fmt(I,2)} A`}else if(kind==='kvaConversion'){const ph=box.querySelector('[data-name="phase"]')?.value;const va=ph==='3'?Math.sqrt(3)*v('voltage')*v('current'):v('voltage')*v('current');html=`容量：${fmt(va,1)} VA / ${fmt(va/1000,3)} kVA`}else if(kind==='voltageDrop'){const ph=box.querySelector('[data-name="phase"]')?.value;const drop=ph==='3'?Math.sqrt(3)*v('current')*v('resistance')*v('length')/1000:2*v('current')*v('resistance')*v('length')/1000;html=`電圧降下：${fmt(drop,2)} V　電圧降下率：${fmt(drop/v('voltage')*100,2)} %`}else if(kind==='voltageDropPercent'){html=`電圧降下率：${fmt(v('drop')/v('voltage')*100,2)} %`}else if(kind==='cableMargin'){html=`ケーブル裕度：${fmt((v('allow')-v('design'))/v('allow')*100,2)} %`}else if(kind==='breakerMargin'){html=`主幹裕度：${fmt((v('breaker')-v('current'))/v('breaker')*100,2)} %`}else if(kind==='conduitFill'){let cableArea=0;for(let i=1;i<=4;i++){const od=v(`od${i}`),ct=v(`count${i}`);if(od&&ct)cableArea+=Math.PI*od*od/4*ct}const pipeArea=Math.PI*v('inner')*v('inner')/4;const fill=cableArea/pipeArea*100;let j32=fill<=32?'OK':'NG';let j48=fill<=48?(fill<=32?'OK':'条件付きOK'):'NG';let overall=fill<=32?'良好':fill<=48?'注意：48%基準では条件付き可、32%基準では不可':'不適合：配管サイズアップ';html=`ケーブル総断面積：${fmt(cableArea,1)} mm²<br>配管内断面積：${fmt(pipeArea,1)} mm²<br>占積率：${fmt(fill,2)} %<br>32%基準：${j32}<br>48%基準：${j48}<br>総合判定：${overall}`}if(String(html).includes('Infinity')||String(html).includes('NaN'))html='未入力または0が含まれています。';box.querySelector('.calc-result').innerHTML=`計算結果：<br>${html}`}
function renderPayload(p,body){if(p.note){const n=document.createElement('div');n.className='field-hint';n.textContent=p.note;body.appendChild(n)}if(p.type==='formula'){const div=document.createElement('div');div.innerHTML=formulaHtml(p.kind);body.appendChild(div.firstElementChild);return}const wrap=document.createElement('div');wrap.className='doc-table-wrap top-gap';const tbl=document.createElement('table');tbl.className='doc-table';const keys=p.keys||(p.rows[0]?Object.keys(p.rows[0]):[]);tbl.innerHTML=`<thead><tr>${(p.headers||keys).map(h=>`<th>${escapeHtml(h)}</th>`).join('')}</tr></thead><tbody>${(p.rows||[]).map(row=>`<tr>${keys.map(k=>`<td>${escapeHtml(row[k]??'-')}</td>`).join('')}</tr>`).join('')}</tbody>`;wrap.appendChild(tbl);body.appendChild(wrap)}
function renderDocs(){const search=($('docsSearch')?.value||'').trim().toLowerCase(),root=$('docsContainer');root.innerHTML='';buildDocs().forEach(g=>{const filtered=[];g.items.forEach(([title,build])=>{const p=build(),blob=`${g.title} ${title} ${p.note||''} ${JSON.stringify(p.rows||{})}`.toLowerCase();if(search&&!blob.includes(search))return;filtered.push([title,p])});if(!filtered.length&&search)return;const gc=document.createElement('div');gc.className='doc-group-card';const gt=document.createElement('button');gt.type='button';gt.className='doc-group-toggle';gt.textContent=`▶ ${g.title}（${filtered.length}件）`;const gb=document.createElement('div');gb.className='stack top-gap';gb.hidden=!search;gt.onclick=()=>{gb.hidden=!gb.hidden;gt.textContent=`${gb.hidden?'▶':'▼'} ${g.title}（${filtered.length}件）`};filtered.forEach(([title,p])=>{const ic=document.createElement('div');ic.className='doc-item-card';const ib=document.createElement('button');ib.type='button';ib.className='doc-item-toggle';ib.textContent=`▶ ${title}`;const body=document.createElement('div');body.className='top-gap';body.hidden=!search;ib.onclick=()=>{body.hidden=!body.hidden;ib.textContent=`${body.hidden?'▶':'▼'} ${title}`};renderPayload(p,body);ic.appendChild(ib);ic.appendChild(body);gb.appendChild(ic)});gc.appendChild(gt);gc.appendChild(gb);root.appendChild(gc)});root.querySelectorAll('.formula-calc-btn').forEach(btn=>btn.addEventListener('click',()=>runFormulaCalc(btn.closest('.formula-box'))));if(!root.children.length)root.innerHTML='<div class="panel muted">該当する資料はありません。</div>'}
function saveCard(item,isHistory){const c=document.createElement('div');c.className='saved-card';const selected=compareIds.includes(item.id);c.innerHTML=`<div class="saved-line"><div class="saved-summary"><div class="saved-title-row"><strong>${escapeHtml(item.title||'無題')}</strong><span class="badge ${item.result?.judgement==='良'?'good':'bad'}">${escapeHtml(item.result?.judgement||'-')}</span></div><span class="muted">${new Date(item.savedAt).toLocaleString('ja-JP')}</span></div></div>${item.memo?`<div class="muted top-gap">${escapeHtml(item.memo)}</div>`:''}<div class="readonly-grid top-gap"><div><span>算出方法</span><strong>${escapeHtml(item.selectionMode==='detailed'?'詳細':'簡易')}</strong></div><div><span>計算方式</span><strong>${calcModeLabel(item.calculationMode)}</strong></div><div><span>採用ケーブル</span><strong>${escapeHtml(item.result?.cableType||'-')} ${item.result?.cableSize?`${item.result.cableSize}sq`:'-'}</strong></div><div><span>合計電流 [A]</span><strong>${fmt(item.result?.totalCurrent,2)}</strong></div><div><span>電圧降下 [%]</span><strong>${fmt(item.result?.voltageDropPercent,2)}</strong></div></div><div class="inline-actions top-gap"><button class="ghost small js-open">この案を開く</button>${isHistory?'<button class="ghost small js-save-history">保存済みに追加</button>':`<button class="ghost small js-compare">${selected?'比較から外す':'比較に追加'}</button>`}${!isHistory?'<button class="ghost small js-rename">名前変更</button>':''}<button class="ghost small js-delete">削除</button></div>`;c.querySelector('.js-open').onclick=()=>openSavedItem(item);c.querySelector('.js-delete').onclick=()=>{if(!confirm('削除しますか？'))return;if(isHistory)historyItems=historyItems.filter(v=>v.id!==item.id);else{savedItems=savedItems.filter(v=>v.id!==item.id);compareIds=compareIds.filter(id=>id!==item.id)}persistState();renderSaved()};if(isHistory)c.querySelector('.js-save-history').onclick=()=>{const cp=structuredClone(item);cp.id=uid();cp.title=`${item.title||'履歴'}_保存`;cp.savedAt=new Date().toISOString();upsertSaved(cp);persistState();renderSaved();toast('保存済みに追加しました。')};else{c.querySelector('.js-compare').onclick=()=>{if(compareIds.includes(item.id))compareIds=compareIds.filter(id=>id!==item.id);else if(compareIds.length<3)compareIds.push(item.id);else return toast('比較は最大3件です。');if(!state.compareBaseId&&compareIds.length)state.compareBaseId=compareIds[0];persistState();renderSaved()};c.querySelector('.js-rename').onclick=()=>{const n=prompt('保存名を入力してください。',item.title||'');if(n&&n.trim()){item.title=n.trim();persistState();renderSaved()}}}return c}
function upsertSaved(item){const idx=savedItems.findIndex(v=>v.title===item.title);if(idx>=0){item.id=savedItems[idx].id;savedItems[idx]=item}else savedItems.unshift(item);if(savedItems.length>MAX_SAVED_ITEMS){const rem=savedItems.slice(MAX_SAVED_ITEMS),ids=new Set(rem.map(v=>v.id));savedItems=savedItems.slice(0,MAX_SAVED_ITEMS);compareIds=compareIds.filter(id=>!ids.has(id))}}
function renderSaved(){const h=$('historyList');if(!h)return;h.innerHTML=historyItems.length?'':'<div class="panel muted">履歴はまだありません。</div>';historyItems.forEach(i=>h.appendChild(saveCard(i,true)));const q=($('savedSearch')?.value||'').trim().toLowerCase();const list=savedItems.filter(i=>!q||`${i.title||''} ${i.memo||''}`.toLowerCase().includes(q));const s=$('savedList');s.innerHTML=list.length?'':'<div class="panel muted">保存済みデータはまだありません。</div>';list.forEach(i=>s.appendChild(saveCard(i,false)));renderCompare()}
function renderCompare(){const sel=$('compareBaseSelect'),view=$('compareView');if(!sel||!view)return;const targets=savedItems.filter(i=>compareIds.includes(i.id));setSelectOptions(sel,targets.map(i=>({value:i.id,label:i.title||'無題'})),'選択してください',state.compareBaseId);$('compareTargetCount').textContent=`${targets.length}件`;view.innerHTML='';if(!targets.length){view.innerHTML='<div class="panel muted">比較対象を追加してください。</div>';return}targets.forEach(i=>{const r=i.result||{};const c=document.createElement('div');c.className='saved-card';c.innerHTML=`<strong>${escapeHtml(i.title||'無題')}</strong><div class="readonly-grid top-gap"><div><span>判定</span><strong>${escapeHtml(r.judgement||'-')}</strong></div><div><span>合計電流[A]</span><strong>${fmt(r.totalCurrent,2)}</strong></div><div><span>主幹[A]</span><strong>${r.adoptedBreaker||'-'}</strong></div><div><span>ケーブル</span><strong>${escapeHtml(r.cableType||'-')} ${r.cableSize?`${r.cableSize}sq`:''}</strong></div><div><span>電圧降下[%]</span><strong>${fmt(r.voltageDropPercent,2)}</strong></div></div>`;view.appendChild(c)})}
function openSavedItem(item){state={...DEFAULT_UI,...structuredClone(item.input||{})};if(!Array.isArray(state.loads))state.loads=[];persistState();renderAll();switchScreen('calc');toast('保存データを開きました。')}
function switchSavedTab(tab){document.querySelectorAll('.saved-seg').forEach(b=>b.classList.toggle('active',b.dataset.savedTab===tab));document.querySelectorAll('.saved-subview').forEach(v=>v.classList.remove('active'));$(`saved-subview-${tab}`)?.classList.add('active')}
function switchScreen(name){Object.entries(screens).forEach(([k,v])=>v?.classList.toggle('active',k===name));document.querySelectorAll('.nav-btn').forEach(b=>b.classList.toggle('active',b.dataset.screen===name));if(name==='docs')renderDocs();if(name==='saved')renderSaved()}
function setVisibleById(id,visible){const e=$(id);if(!e)return;const box=e.closest('label')||e.closest('.readonly-box')||e;e.classList.remove('input-error');box.classList.toggle('is-hidden',!visible)}
function applySelectionModeVisibility(){const simple=state.selectionMode==='simple';$('cablePanel')?.classList.toggle('simple-muted',simple);['cableType','cableSize','baseAmpacity','installationMethod','layingCondition','ambientTemperature','parallelCount'].forEach(id=>setVisibleById(id,!simple));const cb=$('cablePanel');if(cb){let hint=$('simpleModeCableHint');if(!hint){hint=document.createElement('div');hint.id='simpleModeCableHint';hint.className='field-hint simple-mode-hint';cb.prepend(hint)}hint.textContent='簡易選定モードでは、標準条件（配管・一般・40℃・1条）でケーブルを自動候補選定します。詳細条件を指定する場合は詳細選定モードを選択してください。';hint.hidden=!simple}setVisibleById('existingBreaker',state.calcMode==='existing')}
function renderAmpacity(){const co=correctedAmpacity(),cf=coef();$('correctedAmpacityValue').textContent=co?fmt(co,2):'-';$('coefTemperature').textContent=cf.temperature?fmt(cf.temperature,3):'-';$('coefParallel').textContent=cf.parallel?fmt(cf.parallel,3):'-';$('coefMethod').textContent=cf.method?fmt(cf.method,3):'-';$('coefCondition').textContent=cf.condition?fmt(cf.condition,3):'-';$('coefFinal').textContent=cf.final?fmt(cf.final,3):'-';const info=cableInfo(effectiveCableType(),num(state.cableSize)),mpm=info?.massKgKm?num(info.massKgKm)/1000:0;$('massPerMeter').textContent=mpm?fmt(mpm,3):'-';const tm=mpm&&state.wiringLength?mpm*num(state.wiringLength)*num(effectiveSetting('parallelCount')):0;$('massTotal').textContent=tm?fmt(tm,2):'-';$('rackWidthValue').textContent=info?.outerDiameter?rackWidth(num(info.outerDiameter),num(effectiveSetting('parallelCount'))):'-';const badge=$('ampacityModeBadge');badge.className='mode-badge';if(state.ampacityMode==='auto')badge.textContent='自動';else if(state.ampacityMode==='manual'){badge.textContent='手動';badge.classList.add('manual')}else{badge.textContent='未設定';badge.classList.add('none')}}
function applySettings(){$('verAmpacity').textContent=VERSIONS.ampacity;$('verPhysical').textContent=VERSIONS.physical;$('verForm').textContent='2026.04-D';applySelectionModeVisibility()}
function renderAll(){setSelectOptions($('selectionMode'),SELECTION_MODES,'選択してください',state.selectionMode);setSelectOptions($('calcMode'),CALC_MODES,'選択してください',state.calcMode);setSelectOptions($('powerSystem'),['1φ2W','1φ3W','3φ3W','3φ4W'],'選択してください',state.powerSystem);setSelectOptions($('voltage'),['100','200','400','440'],'選択してください',state.voltage);setSelectOptions($('powerFactor'),POWER_FACTOR_OPTIONS,'選択してください',state.powerFactor);setSelectOptions($('efficiency'),EFFICIENCY_OPTIONS,'選択してください',state.efficiency);setSelectOptions($('existingBreaker'),BREAKER_SIZES.map(v=>({value:String(v),label:`${v}A`})),'選択してください',state.existingBreaker);setSelectOptions($('loadCount'),Array.from({length:10},(_,i)=>({value:String(i+1),label:String(i+1)})),'選択してください',state.loadCount);const ct=cableType();setSelectOptions($('cableType'),['CV-1C','CV-2C','CV-3C','CV-4C','CVT'],'選択してください',ct);setSelectOptions($('cableSize'),cableSizes(ct).map(v=>({value:String(v),label:`${v}sq`})),'選択してください',state.cableSize);setSelectOptions($('installationMethod'),['気中','ラック','配管'],'選択してください',state.installationMethod);setSelectOptions($('layingCondition'),['一般','密集','日射あり'],'選択してください',state.layingCondition);setSelectOptions($('ambientTemperature'),[20,25,30,35,40,45,50].map(v=>({value:String(v),label:`${v}℃`})),'選択してください',state.ambientTemperature);setSelectOptions($('parallelCount'),[1,2,3,4,5,6].map(v=>({value:String(v),label:String(v)})),'選択してください',state.parallelCount);['wiringLength','projectName','constructionType','submittedTo','drawingNo','createdBy','projectRemarks','baseAmpacity'].forEach(id=>{if($(id))$(id).value=state[id]||''});$('calcModeHint').textContent=state.selectionMode==='simple'?'簡易選定：標準条件で参考選定します。':(state.calcMode==='existing'?'既設開閉器サイズを基準に幹線サイズを判定します。':'合計負荷容量から必要最小開閉器を算出し、幹線サイズを選定します。');document.querySelectorAll('.seg').forEach(b=>b.classList.toggle('active',b.dataset.calcType===state.calculationType));renderLoadCards();renderAmpacity();renderDocs();renderSaved();applySettings();if(state.lastResult){$('resultPanel')?.classList.remove('hidden');$('resultBody')?.classList.remove('hidden');updateResultError('');renderResult()}}
function bindEvents(){document.querySelectorAll('.nav-btn').forEach(b=>b.addEventListener('click',()=>switchScreen(b.dataset.screen)));document.querySelectorAll('.seg').forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('.seg').forEach(v=>v.classList.remove('active'));b.classList.add('active');state.calculationType=b.dataset.calcType;persistState();renderAll()}));document.querySelectorAll('.saved-seg').forEach(b=>b.addEventListener('click',()=>switchSavedTab(b.dataset.savedTab)));on('selectionMode','change',()=>{state.selectionMode=$('selectionMode').value||'simple';persistState();renderAll()});on('calcMode','change',()=>{state.calcMode=$('calcMode').value;persistState();renderAll()});['powerSystem','voltage','powerFactor','efficiency'].forEach(id=>on(id,'change',()=>{state[id]=$(id).value;persistState();renderLoadCards();renderAmpacity();validateRealtime()}));on('existingBreaker','change',()=>{state.existingBreaker=$('existingBreaker').value;persistState();validateRealtime()});on('loadCount','change',()=>{state.loadCount=$('loadCount').value;normalizeLoads();persistState();renderLoadCards();validateRealtime()});on('cableType','change',()=>{const t=$('cableType').value;applyCableType(t);const sizes=cableSizes(t).map(String);if(!sizes.includes(String(state.cableSize))){state.cableSize='';state.baseAmpacity='';state.ampacityMode='none'}persistState();renderAll()});on('cableSize','change',()=>{state.cableSize=$('cableSize').value;const info=cableInfo(cableType(),num(state.cableSize));state.baseAmpacity=info?.ampacity?String(info.ampacity):'';state.ampacityMode=info?.ampacity?'auto':'none';if($('baseAmpacity'))$('baseAmpacity').value=state.baseAmpacity;persistState();renderAmpacity();validateRealtime()});on('baseAmpacity','input',()=>{state.baseAmpacity=$('baseAmpacity').value;state.ampacityMode=$('baseAmpacity').value?'manual':'none';persistState();renderAmpacity();validateRealtime()});['installationMethod','layingCondition','ambientTemperature','parallelCount'].forEach(id=>on(id,'change',()=>{state[id]=$(id).value;persistState();renderAmpacity();validateRealtime()}));['projectName','constructionType','submittedTo','drawingNo','createdBy','projectRemarks','wiringLength'].forEach(id=>on(id,'input',()=>{state[id]=$(id).value;persistState();if(id==='wiringLength'){renderAmpacity();validateRealtime()}}));on('calculateBtn','click',calculate);on('toggleResultBtn','click',()=>{const body=$('resultBody');body.classList.toggle('hidden');$('toggleResultBtn').textContent=body.classList.contains('hidden')?'展開する':'折りたたむ'});on('saveResultTopBtn','click',openSaveDialog);on('saveResultBottomBtn','click',openSaveDialog);on('confirmSaveBtn','click',e=>{e.preventDefault();confirmSave()});on('csvBtn','click',downloadCsv);on('excelBtn','click',downloadExcel);on('pdfBtn','click',printPdf);on('groundWireBtn','click',()=>$('groundDialog').showModal());on('closeGroundDialog','click',()=>$('groundDialog').close());on('groundType','change',updateGroundResult);on('groundWireType','change',updateGroundResult);on('docsSearch','input',renderDocs);on('openDocsFromCalc','click',()=>switchScreen('docs'));on('returnCalcFromDocs','click',()=>switchScreen('calc'));on('savedSearch','input',renderSaved);on('clearHistoryBtn','click',()=>{if(confirm('履歴をすべて削除しますか？')){historyItems=[];persistState();renderSaved()}});on('resetDisclaimerBtn','click',()=>{localStorage.removeItem(STORAGE.disclaimer);toast('次回起動時に免責を再表示します。')});window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredPrompt=e;$('installBtn').hidden=false});on('installBtn','click',async()=>{if(!deferredPrompt)return;deferredPrompt.prompt();deferredPrompt=null;$('installBtn').hidden=true})}
function validateRealtime(){markMissing(missingFields())}
function openSaveDialog(){if(!state.lastResult)return toast('先に計算してください。');$('saveTitleInput').value=state.projectName||`${calcTypeLabel()}_${new Date().toLocaleString('sv-SE').replace(/[: ]/g,'_')}`;$('saveMemoInput').value=state.projectRemarks||'';$('saveDialog').showModal()}
function confirmSave(){const title=$('saveTitleInput').value.trim();if(!title)return toast('保存名を入力してください。');const existed=savedItems.some(v=>v.title===title);upsertSaved({id:uid(),title,memo:$('saveMemoInput').value.trim(),savedAt:new Date().toISOString(),input:structuredClone(state),result:structuredClone(state.lastResult),calculationMode:state.calcMode,selectionMode:state.selectionMode,versions:structuredClone(VERSIONS)});persistState();renderSaved();$('saveDialog').close();toast(existed?'同名の保存データを上書きしました。':'保存しました。')}
function excelSafe(v){return escapeHtml(v??'').replace(/\n/g,'<br>')}
function commonRows(r){return[['工事件名',state.projectName||''],['工事種別',state.constructionType||calcTypeLabel()],['提出先',state.submittedTo||''],['図番',state.drawingNo||''],['作成日',new Date().toLocaleDateString('ja-JP')],['作成者',state.createdBy||''],['備考',state.projectRemarks||''],['計算区分',calcTypeLabel()],['算出方法',selectionModeLabel()],['計算方式',calcModeLabel()],['電源方式',state.powerSystem],['電圧[V]',state.voltage],['力率',state.powerFactor],['効率',state.efficiency],['配線長[m]',state.wiringLength],['既設開閉器[A]',state.existingBreaker||''],['ケーブル種類',r.cableType],['ケーブルサイズ[sq]',r.cableSize],['基準許容電流[A]',fmt(r.baseAmpacity,2)],['補正後許容電流[A]',fmt(r.correctedAmpacity,2)],['必要最小開閉器[A]',r.requiredBreaker],['採用開閉器[A]',r.adoptedBreaker],['合計容量[kW]',fmt(r.totalKW,3)],['合計容量[kVA]',fmt(r.totalKVA,3)],['合計電流[A]',fmt(r.totalCurrent,2)],['電圧降下[V]',fmt(r.voltageDropV,2)],['電圧降下[%]',fmt(r.voltageDropPercent,2)],['開閉器裕度[%]',fmt(r.breakerMarginPercent,2)],['容量裕度[kW]',fmt(r.capacityMarginKW,2)],['良否判定',r.judgement],['選定主因',r.mainFactor],['選定根拠',(r.reasons||[]).join('、')],['許容電流データ版',VERSIONS.ampacity],['外径・質量データ版',VERSIONS.physical],['帳票様式版','2026.04-D']]}
function downloadExcel(){if(!state.lastResult)return toast('先に計算してください。');const r=state.lastResult,rows=commonRows(r);const loadRows=(r.loadDetails||[]).map((l,i)=>[i+1,l.name,l.inputType,l.value,fmt(l.current,2),fmt(l.kw,3),fmt(l.kva,3)]);const html=`<html><head><meta charset="utf-8"><style>body{font-family:"Yu Gothic",Meiryo,sans-serif}table{border-collapse:collapse;margin-bottom:18px}th,td{border:1px solid #999;padding:6px 8px;mso-number-format:"\\@"}th{background:#eaf2ff}.note{color:#c00;font-weight:bold}</style></head><body><h1>低圧幹線計算書</h1><p class="note">本帳票は参考資料です。内線規定・関係法令・現場仕様・機器仕様を確認し、最終判断は利用者責任で行ってください。</p><h2>計算結果</h2><table>${rows.map(r=>`<tr><th>${excelSafe(r[0])}</th><td>${excelSafe(r[1])}</td></tr>`).join('')}</table><h2>負荷一覧</h2><table><tr><th>No</th><th>負荷名称</th><th>入力方式</th><th>負荷値</th><th>換算電流[A]</th><th>換算容量[kW]</th><th>換算容量[kVA]</th></tr>${loadRows.map(r=>`<tr>${r.map(c=>`<td>${excelSafe(c)}</td>`).join('')}</tr>`).join('')}</table><h2>施工参考メモ</h2><table>${(r.constructionNotes||[]).map(n=>`<tr><td>${excelSafe(n)}</td></tr>`).join('')}</table></body></html>`;const blob=new Blob(['\ufeff'+html],{type:'application/vnd.ms-excel;charset=utf-8;'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`${state.projectName||'feeder_calc'}_${Date.now()}.xls`;a.click();URL.revokeObjectURL(url)}
function downloadCsv(){if(!state.lastResult)return toast('先に計算してください。');const r=state.lastResult;const rows=[['項目','値'],...commonRows(r),[],['負荷No','負荷名称','入力方式','負荷値','換算電流[A]','換算容量[kW]','換算容量[kVA]']];(r.loadDetails||[]).forEach((l,i)=>rows.push([i+1,l.name,l.inputType,l.value,l.current,l.kw,l.kva]));const csv=rows.map(r=>r.map(v=>`"${String(v??'').replace(/"/g,'""')}"`).join(',')).join('\n');const blob=new Blob([csv],{type:'text/csv;charset=utf-8;'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`${state.projectName||'feeder_calc'}_${Date.now()}.csv`;a.click();URL.revokeObjectURL(url)}
function buildPrintReport(){const old=$('printReport');if(old)old.remove();const r=state.lastResult;if(!r)return;const div=document.createElement('div');div.id='printReport';const row=(a,b)=>`<tr><th>${escapeHtml(a)}</th><td>${escapeHtml(b)}</td></tr>`;const inputs=[['計算区分',calcTypeLabel()],['算出方法',selectionModeLabel()],['計算方式',calcModeLabel()],['電源方式',state.powerSystem],['電圧',`${state.voltage} V`],['負荷容量',`${fmt(r.totalKW,3)} kW / ${fmt(r.totalKVA,3)} kVA`],['電線長',`${state.wiringLength} m`],['力率',state.powerFactor],['効率',state.efficiency]];const results=[['合計電流',`${fmt(r.totalCurrent,2)} A`],['選定主幹開閉器',`${r.adoptedBreaker} A`],['選定ケーブル',`${r.cableType} ${r.cableSize}sq`],['基準許容電流',`${fmt(r.baseAmpacity,2)} A`],['補正後許容電流',`${fmt(r.correctedAmpacity,2)} A`],['電圧降下',`${fmt(r.voltageDropV,2)} V`],['電圧降下率',`${fmt(r.voltageDropPercent,2)} %`],['主幹裕度',`${fmt(r.breakerMarginPercent,2)} %`],['総合判定',r.judgement]];div.innerHTML=`<section class="print-page print-summary"><h1>低圧幹線計算書</h1><table class="print-meta">${row('工事件名',state.projectName||'')}${row('工事種別',state.constructionType||calcTypeLabel())}${row('提出先',state.submittedTo||'')}${row('図番',state.drawingNo||'')}${row('作成日',new Date().toLocaleDateString('ja-JP'))}${row('作成者',state.createdBy||'')}</table><h2>入力条件</h2><table>${inputs.map(x=>row(x[0],x[1])).join('')}</table><h2>計算結果</h2><table>${results.map(x=>row(x[0],x[1])).join('')}</table><h2>判定コメント</h2><div class="print-comment">${escapeHtml((r.failReasons&&r.failReasons.length?r.failReasons.join(' / '):'不適合項目はありません。'))}</div><p class="print-note">本計算結果は入力条件に基づく参考選定です。実際の施工・選定にあたっては、内線規定、電気設備技術基準、関係法令、現場仕様、機器仕様、電力会社・監督員指示等を確認し、最終判断は利用者の責任で行ってください。</p></section><section class="print-page print-detail"><h1>詳細資料</h1><h2>各負荷の換算結果</h2><table><tr><th>No</th><th>負荷名称</th><th>入力方式</th><th>負荷値</th><th>電流[A]</th><th>kW</th><th>kVA</th></tr>${(r.loadDetails||[]).map((l,i)=>`<tr><td>${i+1}</td><td>${escapeHtml(l.name||'-')}</td><td>${escapeHtml(l.inputType||'-')}</td><td>${escapeHtml(l.value||'-')}</td><td>${fmt(l.current,2)}</td><td>${fmt(l.kw,3)}</td><td>${fmt(l.kva,3)}</td></tr>`).join('')}</table><h2>補正係数</h2><table>${row('温度補正',fmt(r.correctionBreakdown?.temperature,3))}${row('条数補正',fmt(r.correctionBreakdown?.parallel,3))}${row('敷設方法補正',fmt(r.correctionBreakdown?.method,3))}${row('敷設条件補正',fmt(r.correctionBreakdown?.condition,3))}${row('最終補正係数',fmt(r.correctionBreakdown?.final,3))}</table><h2>施工参考メモ</h2><ul>${(r.constructionNotes||[]).map(n=>`<li>${escapeHtml(n)}</li>`).join('')}</ul><h2>根拠メモ</h2><ul>${(r.rootMemo||[]).map(n=>`<li>${escapeHtml(n)}</li>`).join('')}</ul></section>`;document.body.appendChild(div)}
function printPdf(){if(!state.lastResult)return toast('先に計算してください。');buildPrintReport();if(confirm('PDF印刷用レイアウトを表示します。1ページ目は計算書本体、2ページ目以降は詳細資料です。続行しますか？'))window.print()}
function updateGroundResult(){const gt=$('groundType').value,wt=$('groundWireType').value,br=num(state.lastResult?.adoptedBreaker||state.existingBreaker);const rule=GROUND_RULES.find(v=>v.groundType===gt&&v.wireType===wt&&br<=v.maxBreaker)||GROUND_RULES.find(v=>v.groundType===gt&&v.wireType===wt);$('groundResult').textContent=rule?`採用開閉器 ${br||'-'}A の参考接地線サイズ：${rule.size}`:'条件に合う参考サイズがありません。'}
function runDisclaimer(){if(localStorage.getItem(STORAGE.disclaimer)==='accepted')return;disclaimerStep=1;$('disclaimerTitle').textContent='免責事項';$('disclaimerBody').textContent='本Webアプリおよび帳票出力内容は参考資料です。計算結果は現場条件・仕様・関係法令により変わります。';$('disclaimerDialog').showModal();$('disclaimerNextBtn').onclick=()=>{if(disclaimerStep===1){disclaimerStep=2;$('disclaimerTitle').textContent='重要な確認';$('disclaimerBody').textContent='最終判断は利用者責任で行ってください。内線規定、関係法令、現場条件、機器仕様、保護協調等を必ず確認してください。'}else{localStorage.setItem(STORAGE.disclaimer,'accepted');$('disclaimerDialog').close()}}}
function registerSW(){if('serviceWorker'in navigator)navigator.serviceWorker.register('./sw.js').catch(()=>{})}
function init(){bindEvents();renderAll();switchScreen('calc');switchSavedTab('history');runDisclaimer();registerSW()}
document.addEventListener('DOMContentLoaded',init);
